// Label encoded crop mapping dictionary
const cropMapping = {"Apple": 0, "Banana": 1, "Blackgram": 2, "ChickPea": 3, "Coconut": 4, "Coffee": 5, "Cotton": 6, "Grapes": 7, "Jute": 8, "KidneyBeans": 9, "Lentil": 10, "Maize": 11, "Mango": 12, "MothBeans": 13, "MungBean": 14, "Muskmelon": 15, "Orange": 16, "Papaya": 17, "PigeonPeas": 18, "Pomegranate": 19, "Rice": 20, "Watermelon": 21};

/**
 * Predicts the expected yield of a crop based on input parameters.
 * @param {object} input - { Nitrogen, Phosphorus, Potassium, Temperature, Humidity, pH_Value, Rainfall, Crop }
 * @returns {number} The predicted yield.
 */
export function predictYield(input) {
    // Extract the integer encoding for the crop string name (default to 0 if unknown)
    const cropIdx = cropMapping[input.Crop] || 0;

    // The model expects an array of features in the exact order they were trained:
    // ['Nitrogen', 'Phosphorus', 'Potassium', 'Temperature', 'Humidity', 'pH_Value', 'Rainfall', 'Crop_encoded']
    const features = [
        input.Nitrogen || 0,
        input.Phosphorus || 0,
        input.Potassium || 0,
        input.Temperature || 0,
        input.Humidity || 0,
        input.pH_Value || 0,
        input.Rainfall || 0,
        cropIdx
    ];
    
    // Call the m2cgen generated Regressor function to compute predicted continuous yield
    const predictedYield = score(features);
    
    return predictedYield;
}
